import "@radix-ui/themes/styles.css";
import { Box, ThemePanel, Container, Flex, Section, Heading, Link} from "@radix-ui/themes";
import './App.css';
import { useState } from "react";

class Navigation extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            pagePosition: 0,
            aboutHeight: 0,
            experienceHeight: 0,
            projectsHeight: 0
        }
    }

    render() {
        return (
            <Box>
                <Flex gap="4" mt="7" direction="column">
                    <Link href="#about" weight="bold">ABOUT</Link>
                    <Link href="#experience" weight="bold">EXPERIENCE</Link>
                    <Link href="#projects" weight="bold">PROJECTS</Link>
                </Flex>
            </Box>
        );
    }
}

export default Navigation;
